<template>
    <div v-if="load" class="load"></div>
    <div v-else class="content setting-content">
        <div class="setting-header">
            <div class="setting-title">
                115云盘配置
            </div>
        </div>
        <div class="setting-content-form">
            <n-form :model="cfg" label-placement="top" label-align="left" :label-width="140" :style="{ maxWidth: '640px' }">
                <n-form-item label="Access Token">
                    <n-input type="password" show-password-on="mousedown" v-model:value="cfg.cloud115_token" size="large" placeholder="" clearable />
                </n-form-item>
                <n-form-item label="Refresh Token">
                    <n-input type="password" show-password-on="mousedown" v-model:value="cfg.cloud115_refresh_token" size="large" placeholder="" clearable />
                </n-form-item>
                <n-form-item label="Cookie">
                    <n-input type="password" show-password-on="mousedown" v-model:value="cfg.cloud115_cookie" size="large" placeholder="" clearable />
                </n-form-item>
                <n-form-item label="微信扫码获取Cookie">
                    <n-space vertical>
                        <n-button @click="GetQRCode()" type="info">获取二维码</n-button>
                        <img v-if="qrcode_url" :src="'https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=' + encodeURIComponent(qrcode_url)" style="width:150px;height:150px" />
                    </n-space>
                </n-form-item>
                <n-button size="large" class="btn-save" @click="Save()" type="info">保存</n-button>
            </n-form>
        </div>
    </div>
</template>
<script>
import { getCurrentInstance, onMounted, ref } from "vue";
export default {
    name: "Cloud115Setting",
    setup() {
        const cfg = ref({
            "cloud115_token": null,
            "cloud115_refresh_token": null,
            "cloud115_cookie": null
        })
        const { proxy } = getCurrentInstance();
        const load = ref(true);
        const qrcode_url = ref(null);
        const qr_uid = ref(null);

        function getConfig() {
            proxy.axios.post(proxy.COMMON.apiUrl + `/v1/api/config/data`, {}, {
                headers: {
                    'content-type': 'application/json',
                    'Authorization': proxy.$cookies.get("Authorization")
                }
            }).then(res => {
                if (res.data.code == 200) {
                    cfg.value = res.data.data;
                    load.value = false;
                } else {
                    proxy.COMMON.ShowMsg(res.data.msg)
                    load.value = false;
                }
            }).catch((error) => {
                proxy.COMMON.ShowMsg(error);
                load.value = false;
            });
        }

        function saveConfig() {
            proxy.axios.post(proxy.COMMON.apiUrl + `/v1/api/config/save`, cfg.value, {
                headers: {
                    'content-type': 'application/json',
                    'Authorization': proxy.$cookies.get("Authorization")
                }
            }).then(res => {
                if (res.data.code == 200) {
                    proxy.COMMON.ShowMsg("保存成功")
                } else {
                    proxy.COMMON.ShowMsg(res.data.msg)
                }
            }).catch((error) => {
                proxy.COMMON.ShowMsg(error);
            });
        }

        onMounted(() => {
            getConfig();
        });

        return {
            cfg,
            load,
            qrcode_url,
            qr_uid,
            GetQRCode() {
                let api = proxy.COMMON.apiUrl + '/v1/api/cloud115/qrcode';
                proxy.axios.get(api, {
                    headers: { 'Authorization': proxy.$cookies.get("Authorization") }
                }).then(res => {
                    if (res.data.code == 200) {
                        qrcode_url.value = res.data.data.qrcode;
                        qr_uid.value = res.data.data.uid;
                        proxy.COMMON.ShowMsg("请用微信扫描二维码");
                        PollQRStatus();
                    } else {
                        proxy.COMMON.ShowMsg(res.data.msg)
                    }
                }).catch((error) => {
                    proxy.COMMON.ShowMsg(error);
                });
            },
            PollQRStatus() {
                let interval = setInterval(() => {
                    let api = proxy.COMMON.apiUrl + '/v1/api/cloud115/qrcode/status?uid=' + qr_uid.value;
                    proxy.axios.get(api, {
                        headers: { 'Authorization': proxy.$cookies.get("Authorization") }
                    }).then(res => {
                        if (res.data.code == 200) {
                            if (res.data.data.status == 2) {
                                clearInterval(interval);
                                QRLogin();
                            } else if (res.data.data.status == -1) {
                                clearInterval(interval);
                                proxy.COMMON.ShowMsg("二维码已过期，请重新获取");
                                qrcode_url.value = null;
                            }
                        }
                    }).catch(() => { clearInterval(interval); });
                }, 2000);
            },
            QRLogin() {
                let form = new FormData();
                form.set("uid", qr_uid.value);
                let api = proxy.COMMON.apiUrl + '/v1/api/cloud115/qrcode/login';
                proxy.axios.post(api, form, {
                    headers: { 'Authorization': proxy.$cookies.get("Authorization") }
                }).then(res => {
                    if (res.data.code == 200) {
                        cfg.value.cloud115_cookie = res.data.data.cookie;
                        qrcode_url.value = null;
                        proxy.COMMON.ShowMsg("Cookie获取成功!");
                    } else {
                        proxy.COMMON.ShowMsg(res.data.msg)
                    }
                }).catch((error) => {
                    proxy.COMMON.ShowMsg(error);
                });
            },
            Save() { saveConfig(); }
        }
    }
}
</script>
